import secrets
from cryptography.fernet import Fernet
import base64
import os

def generate_key():
    key = secrets.token_bytes(32)
    return base64.urlsafe_b64encode(key)

def encrypt_credit_card(card_number, key):
    cipher_suite = Fernet(key)
    encrypted_card_number = cipher_suite.encrypt(card_number.encode())
    return encrypted_card_number.decode()

def decrypt_credit_card(encrypted_card_number, key):
    cipher_suite = Fernet(key)
    decrypted_card_number = cipher_suite.decrypt(encrypted_card_number.encode())
    return decrypted_card_number.decode()

# Generate a new encryption key
key = generate_key()
print("Generated Key:", key)

# Store the encryption key securely (e.g., in environment variables or a secure storage service)
os.environ['ENCRYPTION_KEY'] = key

# Example usage:
card_number = "1234567890123456"
encrypted_card_number = encrypt_credit_card(card_number, os.environ['ENCRYPTION_KEY'])
print("Encrypted Card Number:", encrypted_card_number)

decrypted_card_number = decrypt_credit_card(encrypted_card_number, os.environ['ENCRYPTION_KEY'])
print("Decrypted Card Number:", decrypted_card_number)